DDDDLSRC.SOURCE:
@AccessControl.authorizationCheck: #NOT_REQUIRED
@Metadata.allowExtensions: true
@EndUserText.label: 'Upload PO'
define root view entity ZEXED_I_UP_PDCMP
  as select from zexed_up_pdcmp

  association [0..1] to I_BusinessUserBasic as _UserCreate         on $projection.LocalCreatedBy = _UserCreate.UserID

  association [0..1] to I_BusinessUserBasic as _UserChange         on $projection.LocalLastChangedBy = _UserChange.UserID

  association [0..*] to ZEXED_I_UP_PDCMP_I  as _PurchaseOrdersItem on $projection.UUID = _PurchaseOrdersItem.FileUUID

  composition [0..*] of ZEXED_I_UP_PDCMP_H  as _PurchaseOrders
{
  key uuid                                                  as UUID,
      filename                                              as Filename,
      file_size                                             as FileSize,
      file_status                                           as FileStatus,

      case file_status
      when 'Template com erro'          then 1
      when 'Arquivo pronto' then 2
      when 'Excel carregado'            then 3
      else 0
      end                                                   as CriticalityStatus,

      cast( 'sap-icon://excel-attachment' as abap.char(30)) as Icon,
      @Semantics.mimeType: true
      mimetype                                              as Mimetype,
      @Semantics.largeObject: {
        mimeType: 'MimeType',
        fileName: 'Filename',
        contentDispositionPreference: #INLINE
      }
      file_content                                          as FileContent,
      @Semantics.user.createdBy: true
      local_created_by                                      as LocalCreatedBy,

      _UserCreate.PersonFullName                            as NameUserCreate,

      @Semantics.systemDateTime.createdAt: true
      local_created_at                                      as LocalCreatedAt,

      @Semantics.user.lastChangedBy: true
      local_last_changed_by                                 as LocalLastChangedBy,

      _UserChange.PersonFullName                            as NameUserChange,

      @Semantics.systemDateTime.localInstanceLastChangedAt: true
      local_last_changed_at                                 as LocalLastChangedAt,

      @Semantics.systemDateTime.lastChangedAt: true
      last_changed_at                                       as LastChangedAt,
      //Associations
      _PurchaseOrders,
      _PurchaseOrdersItem
}
